// 1. Get the data directly from the Webhook node, not the Supabase input
const webhookData = $("Webhook").first().json;
let urlArray = [];

// ২. ডাটার ভেতর থেকে সব ইউআরএল খুঁজে বের করার ফাংশন
function extractUrlsFromDeep(obj) {
    if (obj !== null && typeof obj === 'object') {
        Object.entries(obj).forEach(([key, value]) => {
            // Meta usually stores the image URL in 'payload.url' inside the messaging array
            if (key === 'payload' && value && typeof value.url === 'string') {
                urlArray.push(value.url);
            } else if (key === 'url' && typeof value === 'string' && value.startsWith('http')) {
                urlArray.push(value);
            } else if (typeof value === 'object') {
                extractUrlsFromDeep(value);
            }
        });
    }
}

// Start scanning the Webhook data
extractUrlsFromDeep(webhookData);

// ৩. ডুপ্লিকেট রিমুভ করা
const uniqueUrls = [...new Set(urlArray)];

// ৪. প্রতিটি ইউআরএল-কে আলাদা আইটেম হিসেবে সাজানো
const finalOutput = uniqueUrls.map(url => {
    return {
        json: {
            image_url: url
        }
    };
});

// BOSS: If no URL is found, we STOP the execution here so the Download node doesn't crash
if (finalOutput.length === 0) {
    return $stopExecution();
}

return finalOutput;

let cleanList = "IDENTIFIED PRODUCTS:\n\n";

// Grab all items from the loop
const items = $input.all();

// 1. Extract the sender_id safely
const senderId = items.length > 0 ? items[0].json.sender_id : "unknown_sender";

// 2. Combine all descriptions using the deep path
items.forEach((item, index) => {
  // NEW PATH: reaches into content.parts[0].text
  const description = item.json.content?.parts?.[0]?.text || "No description found";

  cleanList += `--- PRODUCT ${index + 1} ---\n`;
  cleanList += `${description.trim()}\n\n`;
});

// 3. Return the combined data and the ID
return {
  sender_id: senderId,
  separated_descriptions: cleanList
};

// 1. Grab ALL rows retrieved from Supabase
const items = $input.all();

// 2. Get the current Webhook message ID
const webhookNode = $("Webhook").first();
const currentMid = String(webhookNode.json?.body?.entry?.[0]?.messaging?.[0]?.message?.mid || "").trim().toLowerCase();

if (items.length === 0) {
  return [];
}

// 3. SORT BY TIME (Oldest to Newest)
items.sort((a, b) => {
  return new Date(a.json.created_at) - new Date(b.json.created_at);
});

// 4. THE NULL/EMPTY CHECK (The only reason to stop)
const hasNullOrEmpty = items.some(item => {
  let content = item.json.message_content || item.json.messages || item.json.Message_Content;

  // Success if it's truly null or undefined
  if (content === null || content === undefined) return true;

  // Success if it's the literal string "null" or empty
  let strContent = String(content).trim().toLowerCase();
  return strContent === "" || strContent === "null";
});

// 5. DECISION LOGIC
// If we found a NULL/EMPTY row, we stop here (return empty array)
if (hasNullOrEmpty) {
  return []; 
}

// 6. PREPARE OUTPUT (Since there are no nulls, we proceed!)
const senderId = items[0].json.sender_id;
const idsToUpdate = items.map(item => item.json.id); 

let fullContext = "THE CUSTOMER SENT THE FOLLOWING ITEMS:\n\n";
items.forEach((item, index) => {
  let content = item.json.message_content || item.json.messages || item.json.Message_Content;
  fullContext += `[Item ${index + 1}]: ${content}\n`;
});

return [{
  json: {
    isValid: true,
    sender_id: senderId,
    combined_prompt: fullContext,
    row_ids: idsToUpdate,
    debug: "SUCCESS: No null values found. Proceeding with combined context."
  }
}];

// Clean the output from the AI by removing markdown backticks
let rawOutput = $input.item.json.output;

// Remove triple backticks and the word 'json' if present
rawOutput = rawOutput.replace(/```json|```/g, "").trim();

try {
  // Parse the clean text into real objects
  const parsed = JSON.parse(rawOutput);
  return parsed;

} catch (e) {
  // BOSS: If the AI sends plain Bangla text instead of JSON, this prevents the crash
  // It turns the "messy" text into a valid message your next nodes can understand.
  return [{
    json: {
      type: "text_msg",
      text: rawOutput
    }
  }];
}
